Implementasi Stack yang clean dan type-safe:

```python
from typing import TypeVar, Generic, Optional

T = TypeVar('T')

class Stack(Generic[T]):
    """LIFO stack — Last In, First Out."""

    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        """Tambah item ke top of stack."""
        self._items.append(item)

    def pop(self) -> T:
        """Ambil dan hapus item dari top. Raises IndexError jika kosong."""
        if self.is_empty():
            raise IndexError("pop dari stack kosong")
        return self._items.pop()

    def peek(self) -> T:
        """Lihat top item tanpa menghapus."""
        if self.is_empty():
            raise IndexError("peek dari stack kosong")
        return self._items[-1]

    def is_empty(self) -> bool:
        return len(self._items) == 0

    def __len__(self) -> int:
        return len(self._items)

    def __repr__(self) -> str:
        return f"Stack({self._items})"


# Contoh:
stack: Stack[int] = Stack()
stack.push(1)
stack.push(2)
stack.push(3)
print(stack.peek())   # 3 (tidak terhapus)
print(stack.pop())    # 3
print(len(stack))     # 2
```

Versi ini generic (`Stack[int]`, `Stack[str]`, dll) dan IDE bisa type-check penggunaannya.

Decorator retry yang proper dengan exponential backoff:

```python
import time
import functools
from typing import Callable, Type

def retry(
    max_attempts: int = 3,
    delay: float = 1.0,
    backoff: float = 2.0,
    exceptions: tuple[Type[Exception], ...] = (Exception,),
):
    """Retry decorator dengan exponential backoff."""
    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            current_delay = delay
            last_exception = None

            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e
                    if attempt == max_attempts:
                        break
                    print(f"Attempt {attempt} failed: {e}. Retry in {current_delay:.1f}s...")
                    time.sleep(current_delay)
                    current_delay *= backoff

            raise last_exception
        return wrapper
    return decorator


# Pakai:
@retry(max_attempts=3, delay=1.0, exceptions=(ConnectionError, TimeoutError))
def call_external_api(url: str) -> dict:
    import httpx
    resp = httpx.get(url, timeout=5)
    resp.raise_for_status()
    return resp.json()

# Async version:
import asyncio

def async_retry(max_attempts: int = 3, delay: float = 1.0, backoff: float = 2.0):
    def decorator(func):
        @functools.wraps(func)
        async def wrapper(*args, **kwargs):
            current_delay = delay
            for attempt in range(1, max_attempts + 1):
                try:
                    return await func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts:
                        raise
                    await asyncio.sleep(current_delay)
                    current_delay *= backoff
        return wrapper
    return decorator
```

Library siap pakai: `tenacity` — lebih lengkap dengan jitter, custom callbacks, dll.

Error handling yang baik di Python — dari anti-pattern ke best practice:

**❌ Anti-pattern — catch semua:**
```python
try:
    process_data()
except:
    pass  # Diam-diam gagal — paling berbahaya
```

**✓ Best practice — spesifik, log, re-raise kalau perlu:**
```python
import logging
logger = logging.getLogger(__name__)

def process_order(order_id: int) -> dict:
    try:
        order = db.get_order(order_id)
    except DatabaseConnectionError as e:
        logger.error("DB connection failed", order_id=order_id, exc_info=True)
        raise  # Re-raise — jangan sembunyikan dari caller
    except OrderNotFoundError:
        return {"error": "Order not found", "order_id": order_id}
    except Exception as e:
        logger.critical("Unexpected error", exc_info=True)
        raise RuntimeError(f"Unexpected error processing order {order_id}") from e
    return order
```

**Custom exceptions yang informatif:**
```python
class AppError(Exception):
    """Base exception untuk aplikasi ini."""

class ValidationError(AppError):
    def __init__(self, field: str, message: str) -> None:
        self.field = field
        self.message = message
        super().__init__(f"{field}: {message}")

class ResourceNotFoundError(AppError):
    def __init__(self, resource: str, resource_id) -> None:
        super().__init__(f"{resource} with id={resource_id} not found")

# Pakai:
try:
    user = get_user(123)
except ResourceNotFoundError as e:
    return {"status": 404, "detail": str(e)}
```

**Prinsip:**
1. Tangkap exception spesifik, bukan `Exception` buta
2. Selalu log dengan `exc_info=True` untuk stack trace
3. Jangan sembunyikan error — re-raise atau convert ke error yang meaningful
4. Custom exceptions untuk domain logic yang jelas

