from src.calculator import divide, safe_divide

class TestDivide:
    def test_normal_division(self):
        assert divide(10, 2) == 5.0

    def test_float_result(self):
        assert divide(7, 2) == pytest.approx(3.5)  # float comparison

    def test_negative_numbers(self):
        assert divide(-10, 2) == -5.0

    def test_zero_divisor_raises(self):
        with pytest.raises(ZeroDivisionError, match="Tidak bisa bagi"):
            divide(5, 0)

    @pytest.mark.parametrize("a,b,expected", [
        (10, 2, 5.0),
        (9, 3, 3.0),
        (-6, 2, -3.0),
        (1, 4, 0.25),
    ])
    def test_multiple_cases(self, a, b, expected):
        assert divide(a, b) == pytest.approx(expected)


class TestSafeDivide:
    def test_normal(self):
        assert safe_divide(10, 2) == 5.0

    def test_division_by_zero_returns_default(self):
